from typing import List

def wordBreak(s: str, wordDict: List[str]) -> List[str]:
    if not s:
        return []

    word_set = set(wordDict)
    memo = {}

    def backtrack(current_s: str) -> List[List[str]]:
        if current_s in memo:
            return memo[current_s]

        if not current_s:
            return [[]] 

        results_for_current_s = []

        for i in range(1, len(current_s) + 1):
            word = current_s[:i]
            if word in word_set:
                remaining_sentences_lists = backtrack(current_s[i:])
                for sentence_list in remaining_sentences_lists:
                    results_for_current_s.append([word] + sentence_list)

        memo[current_s] = results_for_current_s
        return results_for_current_s

    all_word_lists = backtrack(s)
    final_sentences = [" ".join(word_list) for word_list in all_word_lists]

    return final_sentences
